function nexlabInstallFinalPolish() {
  if (document.documentElement.dataset.nexlabFinalPolish === "installed") return;
  document.documentElement.dataset.nexlabFinalPolish = "installed";

  const skipLink = document.createElement("a");
  skipLink.href = "#nexlab-main-content";
  skipLink.className = "nexlab-skip-link";
  skipLink.textContent = "Pular para o conteúdo principal";
  document.body.prepend(skipLink);

  const networkBanner = document.createElement("div");
  networkBanner.className = "nexlab-network-banner";
  networkBanner.setAttribute("role", "status");
  networkBanner.setAttribute("aria-live", "polite");
  networkBanner.hidden = true;
  document.body.appendChild(networkBanner);

  const updateNetworkStatus = () => {
    if (navigator.onLine) {
      if (!networkBanner.hidden) {
        networkBanner.textContent = "Conexão restabelecida.";
        networkBanner.classList.add("is-online");
        setTimeout(() => { networkBanner.hidden = true; }, 2500);
      }
      return;
    }
    networkBanner.hidden = false;
    networkBanner.classList.remove("is-online");
    networkBanner.textContent = "Sem conexão. Algumas ações permanecerão indisponíveis até a internet voltar.";
  };

  globalThis.addEventListener("online", updateNetworkStatus);
  globalThis.addEventListener("offline", updateNetworkStatus);
  updateNetworkStatus();

  document.addEventListener("click", (event) => {
    const button = event.target instanceof Element ? event.target.closest("button") : null;
    if (!button || button.disabled || button.dataset.nexlabAllowRapidClick === "true") return;
    if (button.dataset.nexlabClickGuard === "true") {
      event.preventDefault();
      event.stopImmediatePropagation();
      return;
    }
    button.dataset.nexlabClickGuard = "true";
    globalThis.setTimeout(() => {
      delete button.dataset.nexlabClickGuard;
    }, 700);
  }, true);

  const normalizeRuntime = () => {
    const main = document.querySelector("main");
    if (main && !main.id) {
      main.id = "nexlab-main-content";
      main.tabIndex = -1;
    }
    document.querySelectorAll('[class*="fixed"][class*="inset-0"]').forEach((overlay) => {
      if (overlay.querySelector('[role="dialog"], form, [class*="max-w-"]')) {
        overlay.classList.add("nexlab-modal-overlay");
      }
    });
  };

  normalizeRuntime();
  const observer = new MutationObserver(normalizeRuntime);
  observer.observe(document.getElementById("root"), { childList: true, subtree: true });
}

